import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { AuthService } from '../../core/services/auth.service';
import { PresenteService } from '../../core/services/presente.service';
import { ContribuicaoService } from '../../core/services/contribuicao.service';
import { ConviteService } from '../../core/services/convite.service';
import { ToastService } from '../../core/services/toast.service';
import { BrlPipe } from '../../shared/pipes/brl.pipe';
import {
  Presente, PresenteForm, ContribuicaoResponse,
  ConviteResponse, AdminLoginRequest,
} from '../../core/models';

type AdminTab = 'dashboard' | 'presentes' | 'contribuicoes' | 'presencas' | 'mensagens' | 'convites';

@Component({
  selector: 'app-admin',
  standalone: true,
  imports: [CommonModule, FormsModule, BrlPipe],
  templateUrl: './admin.component.html',
  styleUrls: ['./admin.component.scss'],
})
export class AdminComponent implements OnInit {

  // ── Auth ──────────────────────────────────
  loginUser = '';
  loginPass = '';
  loginErr  = '';
  logging   = false;

  // ── Tab ───────────────────────────────────
  activeTab: AdminTab = 'dashboard';

  // ── Presentes ─────────────────────────────
  presentes: Presente[]  = [];
  showGiftForm           = false;
  giftForm: PresenteForm = { nome: '', descricao: '', valor: 0, emoji: '🎁', categoria: 'Cozinha' };
  categorias             = ['Cozinha', 'Quarto', 'Sala', 'Banheiro', 'Viagem', 'Outros'];

  // ── Contribuições ─────────────────────────
  contribuicoes: ContribuicaoResponse[] = [];

  // ── Presenças / Convites ───────────────────
  convites: ConviteResponse[] = [];
  showConviteForm             = false;
  conviteForm                 = { codigo: '', familia: '', convidadosStr: '' };

  // ── Stats (getters) ───────────────────────
  get stats() {
    const cs       = this.conviteSvc.statsSummary();
    const totalVal = this.contribuicaoS.totalArrecadado();
    return {
      totalPresentes:      this.presentes.length,
      presentesReservados: this.presentes.filter(p => p.status === 'RESERVADO').length,
      totalContribuicoes:  this.contribuicoes.length,
      valorTotal:          totalVal,
      ...cs,
    };
  }

  get mensagens(): ContribuicaoResponse[] {
    return this.contribuicoes.filter(c => c.mensagem && c.mensagem.trim());
  }

  get ultimasContribuicoes(): ContribuicaoResponse[] {
    return [...this.contribuicoes].reverse().slice(0, 5);
  }

  constructor(
    public  auth:          AuthService,
    private presenteSvc:   PresenteService,
    private contribuicaoS: ContribuicaoService,
    private conviteSvc:    ConviteService,
    private toastSvc:      ToastService,
  ) {}

  ngOnInit(): void {
    if (this.auth.isLoggedIn()) this.loadData();
  }

  // ── Login ─────────────────────────────────
  login(): void {
    const req: AdminLoginRequest = { username: this.loginUser, password: this.loginPass };
    this.logging  = true;
    this.loginErr = '';
    this.auth.login(req).subscribe({
      next: () => { this.logging = false; this.loadData(); },
      error: () => { this.logging = false; this.loginErr = 'Usuário ou senha incorretos.'; },
    });
  }

  logout(): void { this.auth.logout(); }

  // ── Data ──────────────────────────────────
  loadData(): void {
    this.presenteSvc.listar().subscribe(p => this.presentes = p);
    this.contribuicaoS.listar().subscribe(c => this.contribuicoes = c);
    this.convites = this.conviteSvc.allConvites();
  }

  setTab(tab: AdminTab): void { this.activeTab = tab; }

  // ── Presentes CRUD ────────────────────────
  addPresente(): void {
    if (!this.giftForm.nome.trim() || !this.giftForm.valor) {
      this.toastSvc.error('Preencha nome e valor!');
      return;
    }
    this.presenteSvc.criar({ ...this.giftForm }).subscribe(p => {
      this.presentes    = [...this.presentes, p];
      this.showGiftForm = false;
      this.giftForm     = { nome: '', descricao: '', valor: 0, emoji: '🎁', categoria: 'Cozinha' };
      this.toastSvc.success('"' + p.nome + '" adicionado! 🎁');
    });
  }

  removePresente(id: number): void {
    if (!confirm('Remover este presente?')) return;
    this.presenteSvc.deletar(id).subscribe(() => {
      this.presentes = this.presentes.filter(p => p.id !== id);
      this.toastSvc.success('Presente removido.');
    });
  }

  // ── Convites CRUD ─────────────────────────
  addConvite(): void {
    if (!this.conviteForm.codigo.trim() || !this.conviteForm.familia.trim()) {
      this.toastSvc.error('Preencha código e família!');
      return;
    }
    const convidados = this.conviteForm.convidadosStr
      .split('\n')
      .map((s: string) => s.trim())
      .filter((s: string) => s.length > 0);
    if (convidados.length === 0) {
      this.toastSvc.error('Adicione pelo menos um convidado!');
      return;
    }
    this.conviteSvc.criar({
      codigo:     this.conviteForm.codigo,
      familia:    this.conviteForm.familia,
      convidados,
    }).subscribe(c => {
      this.convites        = [...this.convites, c];
      this.showConviteForm = false;
      this.conviteForm     = { codigo: '', familia: '', convidadosStr: '' };
      this.toastSvc.success('Convite ' + c.codigo + ' criado!');
    });
  }

  removeConvite(id: number): void {
    if (!confirm('Remover este convite?')) return;
    this.conviteSvc.deletar(id).subscribe(() => {
      this.convites = this.convites.filter(c => c.id !== id);
      this.toastSvc.success('Convite removido.');
    });
  }

  // ── Helpers ───────────────────────────────
  confirmadosCount(convite: ConviteResponse): number {
    return convite.convidados.filter(g => g.status === 'CONFIRMADO').length;
  }

  statusClass(status: string): string {
    const map: Record<string, string> = {
      CONFIRMADO: 'badge--confirm',
      TALVEZ:     'badge--maybe',
      NAO_VEM:    'badge--decline',
      PENDENTE:   'badge--pending',
    };
    return map[status] ?? '';
  }

  statusLabel(status: string): string {
    const map: Record<string, string> = {
      CONFIRMADO: '✓ Confirmado',
      TALVEZ:     '? Talvez',
      NAO_VEM:    '✗ Não vem',
      PENDENTE:   '⏳ Pendente',
    };
    return map[status] ?? status;
  }

  pagamentoLabel(forma: string): string {
    return forma === 'PIX' ? '📱 Pix' : '💳 Cartão';
  }

  msgPreview(msg: string): string {
    return msg && msg.length > 40 ? msg.slice(0, 40) + '...' : (msg || '');
  }
}
